/* ──────────────────────────────────────────────────────────────
   flowModel.ts
   Request flow + cost model helpers (AWS estimates by default).
   ────────────────────────────────────────────────────────────── */
import { Edge, Node } from 'react-flow-renderer';
import { ServiceNodeData } from './ServiceNode';
import { ServiceCategory } from './serviceCatalog';

export interface RequestFlow {
  id: string;
  name: string;
  sourceId: string;
  targetId: string;
  rps: number;
  payloadKb: number;
}

export interface CostConfig {
  vcpuPerHr: number;
  memoryGbPerHr: number;
  computePerMReq: number;
  databaseBasePerHr: number;
  databasePerMReq: number;
  streamingBasePerHr: number;
  streamingPerMReq: number;
  analyticsBasePerHr: number;
  analyticsPerMReq: number;
  otherBasePerHr: number;
  otherPerMReq: number;
}

export interface FlowSummary {
  flowId: string;
  name: string;
  pathLabels: string[];
  latencyMs: number;
  monthlyRequests: number;
  perMillionRate: number;
  monthlyCost: number;
  missingPath: boolean;
}

export interface CostTotals {
  baseMonthly: number;
  variableMonthly: number;
  totalMonthly: number;
}

export const DEFAULT_COST_CONFIG: CostConfig = {
  vcpuPerHr: 0.04,
  memoryGbPerHr: 0.005,
  computePerMReq: 0.18,
  databaseBasePerHr: 0.22,
  databasePerMReq: 0.25,
  streamingBasePerHr: 0.6,
  streamingPerMReq: 0.2,
  analyticsBasePerHr: 1.1,
  analyticsPerMReq: 0.35,
  otherBasePerHr: 0.05,
  otherPerMReq: 0.06,
};

const HOURS_PER_MONTH = 730;
const SECONDS_PER_MONTH = 30 * 24 * 60 * 60;

function buildAdjacency(edges: Edge[]): Map<string, string[]> {
  const adj = new Map<string, string[]>();
  for (const e of edges) {
    if (!e.source || !e.target) continue;
    const list = adj.get(e.source) || [];
    list.push(e.target);
    adj.set(e.source, list);
  }
  return adj;
}

function nodeLatency(node: Node<ServiceNodeData>): number {
  return node.data.latency || 0;
}

function findShortestPath(
  startId: string,
  endId: string,
  nodeMap: Map<string, Node<ServiceNodeData>>,
  adj: Map<string, string[]>
): { pathIds: string[]; latency: number } | null {
  if (!nodeMap.has(startId) || !nodeMap.has(endId)) return null;

  const dist = new Map<string, number>();
  const prev = new Map<string, string | null>();
  const unvisited = new Set<string>(nodeMap.keys());

  for (const id of nodeMap.keys()) {
    dist.set(id, Number.POSITIVE_INFINITY);
    prev.set(id, null);
  }

  const startNode = nodeMap.get(startId)!;
  dist.set(startId, nodeLatency(startNode));

  while (unvisited.size > 0) {
    let current: string | null = null;
    let best = Number.POSITIVE_INFINITY;
    for (const id of unvisited) {
      const d = dist.get(id) ?? Number.POSITIVE_INFINITY;
      if (d < best) {
        best = d;
        current = id;
      }
    }

    if (current === null || best === Number.POSITIVE_INFINITY) break;
    unvisited.delete(current);
    if (current === endId) break;

    const neighbors = adj.get(current) || [];
    for (const nb of neighbors) {
      if (!unvisited.has(nb)) continue;
      const nbNode = nodeMap.get(nb);
      if (!nbNode) continue;
      const alt = best + nodeLatency(nbNode);
      if (alt < (dist.get(nb) ?? Number.POSITIVE_INFINITY)) {
        dist.set(nb, alt);
        prev.set(nb, current);
      }
    }
  }

  if ((dist.get(endId) ?? Number.POSITIVE_INFINITY) === Number.POSITIVE_INFINITY) {
    return null;
  }

  const pathIds: string[] = [];
  let cursor: string | null = endId;
  while (cursor) {
    pathIds.unshift(cursor);
    cursor = prev.get(cursor) ?? null;
  }

  return { pathIds, latency: dist.get(endId) ?? 0 };
}

function perMillionReqRate(category: ServiceCategory, config: CostConfig): number {
  switch (category) {
    case 'compute':
    case 'container':
    case 'serverless':
      return config.computePerMReq;
    case 'database':
      return config.databasePerMReq;
    case 'streaming':
      return config.streamingPerMReq;
    case 'analytics':
      return config.analyticsPerMReq;
    default:
      return config.otherPerMReq;
  }
}

function basePerHour(category: ServiceCategory, config: CostConfig): number {
  switch (category) {
    case 'database':
      return config.databaseBasePerHr;
    case 'streaming':
      return config.streamingBasePerHr;
    case 'analytics':
      return config.analyticsBasePerHr;
    default:
      return config.otherBasePerHr;
  }
}

export function nodeMonthlyCost(node: ServiceNodeData, config: CostConfig): number {
  const replicas = Math.max(1, node.replicas ?? 1);
  if (node.vcpus != null || node.memoryGb != null) {
    const vcpuCost = (node.vcpus ?? 0) * config.vcpuPerHr;
    const memCost = (node.memoryGb ?? 0) * config.memoryGbPerHr;
    return (vcpuCost + memCost) * HOURS_PER_MONTH * replicas;
  }

  const hourly = basePerHour(node.category, config);
  return hourly * HOURS_PER_MONTH * replicas;
}

export function computeFlowSummaries(
  flows: RequestFlow[],
  nodes: Node<ServiceNodeData>[],
  edges: Edge[],
  config: CostConfig
): { summaries: FlowSummary[]; totals: CostTotals } {
  const nodeMap = new Map(nodes.map((n) => [n.id, n]));
  const adj = buildAdjacency(edges);

  const baseMonthly = nodes.reduce(
    (sum, n) => sum + nodeMonthlyCost(n.data as ServiceNodeData, config),
    0
  );

  let variableMonthly = 0;
  const summaries: FlowSummary[] = flows.map((flow) => {
    if (!flow.sourceId || !flow.targetId) {
      return {
        flowId: flow.id,
        name: flow.name,
        pathLabels: [],
        latencyMs: 0,
        monthlyRequests: 0,
        perMillionRate: 0,
        monthlyCost: 0,
        missingPath: true,
      };
    }

    const result = findShortestPath(flow.sourceId, flow.targetId, nodeMap, adj);
    if (!result) {
      return {
        flowId: flow.id,
        name: flow.name,
        pathLabels: [],
        latencyMs: 0,
        monthlyRequests: 0,
        perMillionRate: 0,
        monthlyCost: 0,
        missingPath: true,
      };
    }

    const pathLabels = result.pathIds.map((id) => {
      const node = nodeMap.get(id);
      if (!node) return id;
      const data = node.data as ServiceNodeData;
      return data.instanceLabel ? `${data.label} (${data.instanceLabel})` : data.label;
    });

    const perMillionRate = result.pathIds.reduce((sum, id) => {
      const node = nodeMap.get(id);
      if (!node) return sum;
      return sum + perMillionReqRate((node.data as ServiceNodeData).category, config);
    }, 0);

    const monthlyRequests = Math.max(0, flow.rps) * SECONDS_PER_MONTH;
    const monthlyCost = (monthlyRequests / 1_000_000) * perMillionRate;
    variableMonthly += monthlyCost;

    return {
      flowId: flow.id,
      name: flow.name,
      pathLabels,
      latencyMs: Math.round(result.latency),
      monthlyRequests,
      perMillionRate,
      monthlyCost,
      missingPath: false,
    };
  });

  return {
    summaries,
    totals: {
      baseMonthly,
      variableMonthly,
      totalMonthly: baseMonthly + variableMonthly,
    },
  };
}
